def solve(arg1: dict) -> dict:
    username = arg1.get('username')
    password = arg1.get('password')

    if not username:
        return {'status': 'error', 'message': 'Username is required.'}
    if not password:
        return {'status': 'error', 'message': 'Password is required.'}

    # Simulated user validation
    valid_user = username == 'validUser' and password == 'validPassword'
    if valid_user:
        return {'status': 'success', 'roles': ['user', 'admin']}
    else:
        return {'status': 'error', 'message': 'Invalid username or password.'}

def role_lookup(arg1: dict) -> dict:
    username = arg1.get('username')
    if username == 'validUser':
        return {'roles': ['user', 'admin']}
    return {}
